output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?label WHERE {
  wd:Q55452735 rdfs:label ?label
  FILTER(LANG(?label) = 'en')
}

args.sparql:
SELECT DISTINCT ?court ?label WHERE { 
  ?court wdt:P31/wdt:P279* wd:Q3347889; 
          wdt:P17 wd:Q35; 
          rdfs:label ?label . 
  FILTER(LANG(?label) = "en") 
  FILTER(CONTAINS(LCASE(?label), "debt") || CONTAINS(LCASE(?label), "relief")) 
} LIMIT 5

SELECT ?court ?label WHERE { 
  ?court rdfs:label "Gældsboligretten"@da . 
  ?court rdfs:label ?label . 
  FILTER(LANG(?label) = "en") 
} LIMIT 1
